import org.apache.camel.spi.UriParams;
import org.apache.camel.spi.UriPath;

@UriParams
public class FixConfiguration implements Cloneable {

    @UriPath(description = "The FIX session ID")
    @Metadata(required = true)
    private String sessionID;

    @UriParam(label = "common", description = "Path to FIX configuration file")
    private String configFile;

    @UriParam(label = "common", description = "Sender company ID")
    private String senderCompID;

    @UriParam(label = "common", description = "Target company ID")
    private String targetCompID;

    @UriParam(label = "common", description = "FIX protocol version")
    private String fixVersion;

    @UriParam(label = "common", defaultValue = "30", description = "Heartbeat interval in seconds")
    private Integer heartBeatInterval = 30;

    @UriParam(label = "common", description = "Socket connection host")
    private String socketConnectHost;

    @UriParam(label = "common", description = "Socket connection port")
    private Integer socketConnectPort;

    @UriParam(label = "common", defaultValue = "true", description = "Whether to use data dictionary")
    private Boolean useDataDictionary = true;

    public FixConfiguration() {
    }

    public FixConfiguration copy() {
        try {
            return (FixConfiguration) clone();
        } catch (CloneNotSupportedException e) {
            throw new RuntimeException(e);
        }
    }

    public String getSessionID() {
        return sessionID;
    }

    public void setSessionID(String sessionID) {
        this.sessionID = sessionID;
    }

    public String getConfigFile() {
        return configFile;
    }

    public void setConfigFile(String configFile) {
        this.configFile = configFile;
    }

    public String getSenderCompID() {
        return senderCompID;
    }

    public void setSenderCompID(String senderCompID) {
        this.senderCompID = senderCompID;
    }

    public String getTargetCompID() {
        return targetCompID;
    }

    public void setTargetCompID(String targetCompID) {
        this.targetCompID = targetCompID;
    }

    public String getFixVersion() {
        return fixVersion;
    }

    public void setFixVersion(String fixVersion) {
        this.fixVersion = fixVersion;
    }

    public Integer getHeartBeatInterval() {
        return heartBeatInterval;
    }

    public void setHeartBeatInterval(Integer heartBeatInterval) {
        this.heartBeatInterval = heartBeatInterval;
    }

    public String getSocketConnectHost() {
        return socketConnectHost;
    }

    public void setSocketConnectHost(String socketConnectHost) {
        this.socketConnectHost = socketConnectHost;
    }

    public Integer getSocketConnectPort() {
        return socketConnectPort;
    }

    public void setSocketConnectPort(Integer socketConnectPort) {
        this.socketConnectPort = socketConnectPort;
    }

    public Boolean isUseDataDictionary() {
        return useDataDictionary;
    }

    public void setUseDataDictionary(Boolean useDataDictionary) {
        this.useDataDictionary = useDataDictionary;
    }
}

