package org.apache.camel.component.fix;

import org.apache.camel.Component;
import org.apache.camel.test.junit5.CamelTestSupport;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertThrows;

public class FixComponentTest extends CamelTestSupport {

    @Test
    public void testFixComponentCreation() {
        Component component = context().getComponent("fix", FixComponent.class);
        assertNotNull(component);
    }

    @Test
    public void testFixComponentUri() throws Exception {
        FixComponent component = context().getComponent("fix", FixComponent.class);
        component.setSenderCompID("SENDER");
        component.setTargetCompID("TARGET");

        FixEndpoint endpoint = (FixEndpoint) component.createEndpoint("fix:TEST-SESSION");
        assertNotNull(endpoint);
        assertNotNull(endpoint.getSessionID());
    }

    @Test
    public void testFixComponentMissingSessionID() {
        FixComponent component = context().getComponent("fix", FixComponent.class);

        assertThrows(IllegalArgumentException.class, () -> {
            component.createEndpoint("fix:");
        });
    }
}

